import{_ as t,c as o,o as a,ag as r}from"./chunks/framework.Bw-5EFTY.js";const g=JSON.parse('{"title":"DAG Server Core Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-server-core/SPEC.md","filePath":"packages/dag-server-core/SPEC.md"}'),d={name:"packages/dag-server-core/SPEC.md"};function c(i,e,s,n,l,p){return a(),o("div",null,e[0]||(e[0]=[r('<h1 id="dag-server-core-specification" tabindex="-1">DAG Server Core Specification <a class="header-anchor" href="#dag-server-core-specification" aria-label="Permalink to &quot;DAG Server Core Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns reusable DAG server bootstrap, shared server composition, runtime assembly, asset management, file-based storage, and bundled node catalog behavior. Provides a ready-to-run Express server that wires <code>dag-api</code> controllers with in-memory or file-backed ports and exposes REST endpoints plus SSE-based run progress streaming.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Depends on <code>dag-core</code> for domain contracts, port interfaces, in-memory ports, and lifecycle executor.</li><li>Depends on <code>dag-api</code> for controller composition and execution composition (known sibling dependency).</li><li>Does not own DAG domain contracts (<code>IDagDefinition</code>, <code>IDagRun</code>, state machines) -- those belong to <code>dag-core</code>.</li><li>Does not own controller logic or API contract shapes -- those belong to <code>dag-api</code>.</li><li>Keeps reusable server wiring separate from app-specific deployment concerns.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><ul><li><strong><code>startDagServer(options)</code></strong> (<code>dag-server-bootstrap.ts</code>): The main entrypoint. Creates an Express app with CORS, JSON parsing, Swagger UI, and wires all DAG endpoints: <ul><li>Definition CRUD endpoints (<code>/v1/dag/definitions/...</code>)</li><li>Run endpoints (<code>/v1/dag/runs/...</code>) including create, start, query result, and SSE progress streaming</li><li>Asset endpoints (<code>/v1/dag/assets/...</code>) for upload, reference creation, metadata, and content serving</li><li>Node catalog endpoint (<code>/v1/dag/nodes</code>)</li><li>OpenAPI documentation (<code>/api-docs</code>)</li></ul></li><li><strong><code>DagRunService</code></strong> (<code>dag-run-service.ts</code>): Orchestrates the full run lifecycle: creates a definition copy, publishes it, creates and starts a run, processes tasks until terminal, and maps results to traces with cost data. Also handles artifact cleanup.</li><li><strong><code>AssetAwareTaskExecutorPort</code></strong> (<code>asset-aware-task-executor.ts</code>): Decorator for <code>ITaskExecutorPort</code> that intercepts binary outputs and stores them as asset references via <code>IAssetStore</code>.</li><li><strong><code>FileStoragePort</code></strong> (<code>file-storage-port.ts</code>): File-system-backed <code>IStoragePort</code> implementation. Definitions persist as JSON files; runs and tasks are in-memory.</li><li><strong><code>BundledNodeCatalogService</code></strong> (<code>bundled-node-catalog-service.ts</code>): Implements <code>INodeCatalogService</code> from <code>dag-api</code> using a static list of node manifests.</li><li><strong><code>DAG_OPENAPI_DOCUMENT</code></strong> (<code>docs/openapi-dag.ts</code>): OpenAPI 3.0.3 specification object for all DAG endpoints.</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IDagServerBootstrapOptions</code> -- server bootstrap configuration (port, manifests, lifecycle factories, asset store, storage root, etc.)</li><li><code>IAssetStore</code> -- asset storage contract (save, saveReference, getMetadata, getContent, initialize?)</li><li><code>IStoredAssetMetadata</code> -- stored asset metadata (assetId, fileName, mediaType, sizeBytes, createdAt, sourceUri?, binaryKind?)</li><li><code>ICreateAssetInput</code> -- asset upload input (fileName, mediaType, content Buffer)</li><li><code>ICreateAssetReferenceInput</code> -- asset reference input (fileName, mediaType, sourceUri, binaryKind, sizeBytes?)</li><li><code>IAssetContentResult</code> -- asset content result (stream, metadata)</li><li><code>IDagRunServiceOptions</code> -- run service configuration</li><li><code>IRunResult</code> -- run result with traces and total cost</li><li><code>IRunNodeTrace</code> -- per-node trace (nodeId, nodeType, input, output, estimatedCostUsd, totalCostUsd)</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><ul><li><code>startDagServer(options): Promise&lt;{ app, server, storage }&gt;</code> -- bootstrap and start the Express server</li><li><code>DagRunService</code> -- full run lifecycle service <ul><li><code>createRun(definition, input)</code>, <code>startRunById(dagRunId)</code>, <code>getRunResult(dagRunId)</code></li><li><code>deleteRunArtifacts(dagRunId)</code>, <code>deleteDefinitionArtifacts(dagId, version?)</code>, <code>deleteRunCopyArtifacts()</code></li></ul></li><li><code>AssetAwareTaskExecutorPort</code> -- task executor decorator for asset storage</li><li><code>FileStoragePort</code> -- file-system <code>IStoragePort</code> implementation</li><li><code>BundledNodeCatalogService</code> -- static node catalog <code>INodeCatalogService</code> implementation</li><li><code>DAG_OPENAPI_DOCUMENT</code> -- OpenAPI specification object</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>IAssetStore</code> -- implement to provide custom asset storage (e.g., S3, cloud storage). Must implement <code>save</code>, <code>saveReference</code>, <code>getMetadata</code>, <code>getContent</code>.</li><li><code>INodeLifecycleFactory</code> / <code>INodeManifestRegistry</code> (from <code>dag-core</code>) -- provide node manifest and lifecycle factory registrations via bootstrap options.</li><li><code>FileStoragePort</code> can be replaced with any <code>IStoragePort</code> implementation for production use.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>Errors are mapped to <code>IProblemDetails</code> (from <code>dag-api</code>) at the Express route level.</p><p><code>DagRunService</code>-specific validation errors (<code>category: &#39;validation&#39;</code>):</p><ul><li><code>DAG_VALIDATION_RUN_NOT_TERMINAL</code> -- run is not yet in a terminal state for result retrieval</li><li><code>DAG_VALIDATION_DAG_RUN_NOT_FOUND</code> -- run not found for deletion</li><li><code>DAG_VALIDATION_DEFINITION_NOT_FOUND</code> -- definition not found for deletion</li><li><code>DAG_VALIDATION_RUN_TRACE_NODE_TYPE_NOT_FOUND</code> -- node type missing in trace mapping</li><li><code>DAG_VALIDATION_RUN_TRACE_SNAPSHOT_MISSING</code> / <code>_INVALID</code> / <code>_PARSE_FAILED</code> -- snapshot errors</li><li><code>DAG_VALIDATION_RUN_TRACE_COST_MISSING</code> -- cost fields missing in trace</li><li><code>DAG_VALIDATION_RUN_FAILED_WITHOUT_TASK</code> -- run failed but no failed task found</li><li><code>DAG_VALIDATION_RUN_FAILURE_DETAILS_MISSING</code> -- failed task missing error details</li><li><code>DAG_VALIDATION_DEFINITION_SNAPSHOT_MISSING</code> / <code>_INVALID</code> / <code>_PARSE_FAILED</code> -- definition snapshot errors</li></ul><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>ITaskExecutorPort</code> (dag-core)</td><td><code>AssetAwareTaskExecutorPort</code></td><td>production (decorator)</td><td><code>src/asset-aware-task-executor.ts</code></td></tr><tr><td><code>IStoragePort</code> (dag-core)</td><td><code>FileStoragePort</code></td><td>production</td><td><code>src/file-storage-port.ts</code></td></tr><tr><td><code>INodeCatalogService</code> (dag-api)</td><td><code>BundledNodeCatalogService</code></td><td>production</td><td><code>src/bundled-node-catalog-service.ts</code></td></tr></tbody></table><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Classes are standalone.</p><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Adapter</th><th>Location</th></tr></thead><tbody><tr><td><code>ITaskExecutorPort</code> (dag-core)</td><td><code>AssetAwareTaskExecutorPort</code></td><td><code>src/asset-aware-task-executor.ts</code></td></tr><tr><td><code>IStoragePort</code> (dag-core)</td><td><code>FileStoragePort</code></td><td><code>src/file-storage-port.ts</code></td></tr><tr><td><code>INodeCatalogService</code> (dag-api)</td><td><code>BundledNodeCatalogService</code></td><td><code>src/bundled-node-catalog-service.ts</code></td></tr><tr><td><code>INodeLifecycleFactory</code> (dag-core)</td><td><code>startDagServer</code> (via DI)</td><td><code>src/dag-server-bootstrap.ts</code></td></tr><tr><td><code>INodeManifestRegistry</code> (dag-core)</td><td><code>startDagServer</code> (via DI)</td><td><code>src/dag-server-bootstrap.ts</code></td></tr><tr><td>Controller composition (dag-api)</td><td><code>startDagServer</code></td><td><code>src/dag-server-bootstrap.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Unit tests</strong>: <code>dag-server-bootstrap.helpers.test.ts</code></li><li>Tests validate server bootstrap helper logic.</li><li>Integration testing is expected through <code>dag-api</code> E2E tests and app-level server tests.</li><li>Coverage focus: run lifecycle (create, start, process, result), asset reference mapping, file storage atomic writes, node catalog service.</li><li>Run: <code>pnpm --filter @robota-sdk/dag-server-core test</code></li></ul>',27)]))}const h=t(d,[["render",c]]);export{g as __pageData,h as default};
